{
	char Buff[255];
	GetWindowTextA(hWnd, Buff, 254);
	
	char class_name[80];
	char title[80];
	GetClassNameA(hWnd, class_name, sizeof(class_name));
	GetWindowTextA(hWnd, title, sizeof(title));
	
	if(strncmp(Buff,winMatch.c_str(),10) == 0)
	{
		std::cout << "Found window : """ << title << """ [" << class_name << "] " << std::endl << std::endl;
		foundHwnd = hWnd;
	}
		
	return true;
}

